"use client"

import { useRef, useState, useEffect } from "react"
import Link from "next/link"
import { useAuth } from "@/lib/auth-context"
import { Button } from "@/components/ui/button"
import { Sheet, SheetContent, SheetTrigger, SheetTitle } from "@/components/ui/sheet"
import {
  NavigationMenu,
  NavigationMenuContent,
  NavigationMenuItem,
  NavigationMenuList,
  NavigationMenuTrigger,
} from "@/components/ui/navigation-menu"
import {
  Menu,
  Layers,
  CreditCard,
  Globe,
  HelpCircle,
  User,
  Home,
  Sparkles,
  Building2,
  Newspaper,
  Briefcase,
  Phone,
  PhoneCall,
  Wifi,
  History,
  Store,
  Shield,
  Trophy,
  Megaphone,
  BarChart3,
  ChevronDown,
  Zap,
  Signal,
  Grid3X3,
  Info,
  LifeBuoy,
  MessageSquare,
  FileText
} from "lucide-react"
import { cn } from "@/lib/utils"

export function Header() {
  const { user } = useAuth()
  const [isOpen, setIsOpen] = useState(false)
  const [scrolled, setScrolled] = useState(false)
  const [moreOpen, setMoreOpen] = useState(false)
  const moreDropdownRef = useRef<HTMLDivElement>(null)

  // Handle click outside to close "More" dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (moreDropdownRef.current && !moreDropdownRef.current.contains(event.target as Node)) {
        setMoreOpen(false)
      }
    }

    if (moreOpen) {
      document.addEventListener('mousedown', handleClickOutside)
      return () => document.removeEventListener('mousedown', handleClickOutside)
    }
  }, [moreOpen])

  // Staggered animation for nav items
  const navItemAnimation = (index: number) => ({
    animationDelay: `${index * 75}ms`,
  })

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20)
    }
    window.addEventListener("scroll", handleScroll)
    return () => window.removeEventListener("scroll", handleScroll)
  }, [])

  // Main navigation - 4 primary categories
  const mainNavLinks = [
    { href: "/", label: "Home", icon: Home, color: "bg-blue-500/10 text-blue-600" },
    { href: "#services", label: "Services", icon: Grid3X3, color: "bg-primary/10 text-primary", hasDropdown: true },
    { href: "/about", label: "Company", icon: Building2, color: "bg-purple-500/10 text-purple-600", hasDropdown: true },
    { href: "/faq", label: "Support", icon: LifeBuoy, color: "bg-emerald-500/10 text-emerald-600", hasDropdown: true },
  ]

  // Services submenu items
  const servicesItems = [
    { href: "/dashboard/airtime", label: "Airtime", description: "Instant top-up for all networks", icon: Phone, color: "bg-yellow-500/10 text-yellow-600" },
    { href: "/dashboard/data", label: "Data Bundles", description: "Affordable data packages", icon: Wifi, color: "bg-blue-500/10 text-blue-600" },
    { href: "/dashboard/verification", label: "Verification", description: "SIM and number verification", icon: PhoneCall, color: "bg-green-500/10 text-green-600" },
    { href: "/dashboard/result-checkers", label: "Result Checkers", description: "Exam result checking", icon: CreditCard, color: "bg-purple-500/10 text-purple-600" },
    { href: "#features", label: "Features", description: "Explore all capabilities", icon: Sparkles, color: "bg-pink-500/10 text-pink-600" },
    { href: "#networks", label: "Networks", description: "MTN, Vodafone, AirtelTigo", icon: Signal, color: "bg-orange-500/10 text-orange-600" },
  ]

  // Company submenu items
  const companyItems = [
    { href: "/about", label: "About Us", description: "Our story and mission", icon: Info },
    { href: "/blog", label: "Blog", description: "News and updates", icon: Newspaper },
    { href: "/careers", label: "Careers", description: "Join our team", icon: Briefcase },
  ]

  // Support submenu items
  const supportItems = [
    { href: "/faq", label: "FAQ", description: "Common questions", icon: HelpCircle },
    { href: "/contact", label: "Contact", description: "Get in touch", icon: MessageSquare },
    { href: "/terms", label: "Terms", description: "Terms of service", icon: FileText },
  ]

  // More dropdown items (secondary navigation)
  const moreItems = [
    { href: "/dashboard/history", label: "History", icon: History },
    { href: "/dashboard/reseller", label: "Reseller", icon: Store },
    { href: "/dashboard/reseller/security", label: "Security", icon: Shield },
    { href: "/dashboard/reseller/tiers", label: "Tiers", icon: Trophy },
    { href: "/dashboard/reseller/marketing", label: "Marketing", icon: Megaphone },
    { href: "/dashboard/reseller/analytics", label: "Analytics", icon: BarChart3 },
  ]

  // Dashboard services for mobile menu
  const dashboardServices = [
    { href: "/dashboard/airtime", label: "Airtime", icon: Phone },
    { href: "/dashboard/data", label: "Data", icon: Wifi },
    { href: "/dashboard/verification", label: "Verification", icon: PhoneCall },
    { href: "/dashboard/history", label: "History", icon: History },
    { href: "/dashboard/result-checkers", label: "Result Checkers", icon: CreditCard },
    { href: "/dashboard/reseller", label: "Reseller", icon: Store },
    { href: "/dashboard/reseller/security", label: "Security", icon: Shield },
    { href: "/dashboard/reseller/tiers", label: "Tiers", icon: Trophy },
    { href: "/dashboard/reseller/marketing", label: "Marketing", icon: Megaphone },
    { href: "/dashboard/reseller/analytics", label: "Analytics", icon: BarChart3 },
  ]

  return (
    <header
      className={cn(
        "fixed top-0 left-0 right-0 z-50 transition-all duration-500 ease-out",
        scrolled
          ? "bg-white/95 backdrop-blur-xl border-b border-slate-200/80 shadow-sm shadow-slate-200/50 py-2"
          : "bg-gradient-to-b from-white/90 to-white/60 backdrop-blur-md border-b border-white/20 py-3"
      )}
    >
      <div className="container mx-auto px-4">
        <div className="flex items-center justify-between">
          {/* Logo & System Status */}
          <div className="flex items-center gap-4 lg:gap-6">
            <Link href="/" className="flex items-center gap-2 group">
              <div className="flex items-center">
                <div className="relative">
                  <span className="font-heading text-xl lg:text-2xl font-bold tracking-tight bg-gradient-to-r from-blue-600 to-blue-500 bg-clip-text text-transparent group-hover:from-blue-700 group-hover:to-blue-600 transition-all duration-300">
                    Topchart
                  </span>
                </div>
                <span className="ml-1.5 text-[9px] font-bold uppercase tracking-widest text-white bg-gradient-to-r from-blue-600 to-blue-500 px-2 py-0.5 rounded-full shadow-sm">
                  GH
                </span>
              </div>
              {scrolled && (
                <div className="hidden xl:flex items-center gap-1.5 animate-fade-in ml-3 px-2 py-1 rounded-full bg-emerald-50 border border-emerald-200">
                  <div className="h-1.5 w-1.5 rounded-full bg-emerald-500 animate-pulse" />
                  <span className="text-[10px] font-semibold uppercase tracking-wider text-emerald-700">Online</span>
                </div>
              )}
            </Link>

            {/* Desktop Navigation - Compact */}
            <nav className="hidden xl:flex items-center">
              {mainNavLinks.map((link) => (
                <div key={link.label} className="relative group">
                  {link.hasDropdown ? (
                    <NavigationMenu className="relative z-50">
                      <NavigationMenuList>
                        <NavigationMenuItem>
                          <NavigationMenuTrigger className="px-3 py-2 text-sm font-medium text-slate-600 hover:text-blue-600 bg-transparent hover:bg-blue-50/50 rounded-lg transition-all duration-200 data-[state=open]:bg-blue-50 data-[state=open]:text-blue-600">
                            <span className="flex items-center gap-1.5">
                              <link.icon className="h-3.5 w-3.5" />
                              {link.label}
                            </span>
                          </NavigationMenuTrigger>
                          <NavigationMenuContent className="absolute top-full left-0 mt-1.5">
                            <div className="w-[360px] p-4 bg-white rounded-xl shadow-2xl shadow-slate-200/60 border border-slate-100 animate-in fade-in zoom-in-95 duration-200">
                              <div className="grid gap-0.5">
                                {(link.label === "Services" ? servicesItems :
                                  link.label === "Company" ? companyItems :
                                  supportItems).map((item, idx) => {
                                  const Icon = item.icon
                                  return (
                                    <Link
                                      key={item.href}
                                      href={item.href}
                                      className="flex items-start gap-3 p-2.5 rounded-lg hover:bg-blue-50/70 transition-all duration-200 group/item animate-in slide-in-from-left-2 fill-mode-backwards"
                                      style={{ animationDelay: `${idx * 40}ms` }}
                                    >
                                      <div className={cn("p-2 rounded-lg shrink-0 transition-transform duration-200 group-hover/item:scale-110", item.color || "bg-slate-100")}>
                                        <Icon className="h-4 w-4" />
                                      </div>
                                      <div>
                                        <p className="text-sm font-medium text-slate-800 group-hover/item:text-blue-600 transition-colors">
                                          {item.label}
                                        </p>
                                        <p className="text-xs text-slate-500">{item.description}</p>
                                      </div>
                                    </Link>
                                  )
                                })}
                              </div>
                            </div>
                          </NavigationMenuContent>
                        </NavigationMenuItem>
                      </NavigationMenuList>
                    </NavigationMenu>
                  ) : (
                    <Link
                      href={link.href}
                      className="px-3 py-2 text-sm font-medium text-slate-600 hover:text-blue-600 transition-all duration-200 rounded-lg hover:bg-blue-50/50 flex items-center gap-1.5"
                    >
                      <link.icon className="h-3.5 w-3.5" />
                      {link.label}
                    </Link>
                  )}
                </div>
              ))}

              {/* More Dropdown - Compact */}
              <div ref={moreDropdownRef} className="relative z-50">
                <button 
                  onClick={() => setMoreOpen(!moreOpen)}
                  className="px-3 py-2 text-sm font-medium text-slate-600 hover:text-blue-600 transition-all duration-200 rounded-lg hover:bg-blue-50/50 flex items-center gap-1.5"
                  aria-expanded={moreOpen}
                >
                  <Layers className="h-3.5 w-3.5" />
                  More
                  <ChevronDown className={cn("h-3 w-3 transition-transform duration-200", moreOpen && "rotate-180")} />
                </button>
                {moreOpen && (
                  <div className="absolute top-full left-0 mt-1.5 w-[280px] bg-white rounded-xl shadow-2xl shadow-slate-200/60 border border-slate-100 p-3 animate-in fade-in zoom-in-95 slide-in-from-top-2 duration-200 z-50">
                    <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2 px-2">Dashboard</p>
                    <div className="grid grid-cols-2 gap-0.5">
                      {moreItems.map((item, idx) => {
                        const Icon = item.icon
                        return (
                          <Link
                            key={item.href}
                            href={item.href}
                            onClick={() => setMoreOpen(false)}
                            className="flex items-center gap-2 px-2.5 py-2 rounded-lg hover:bg-blue-50/70 transition-all duration-200 text-sm font-medium text-slate-600 hover:text-blue-600 animate-in slide-in-from-left-2 fill-mode-backwards"
                            style={{ animationDelay: `${idx * 25}ms` }}
                          >
                            <Icon className="h-3.5 w-3.5 shrink-0" />
                            <span className="truncate">{item.label}</span>
                          </Link>
                        )
                      })}
                    </div>
                  </div>
                )}
              </div>
            </nav>
          </div>

          {/* Right Side Actions */}
          <div className="flex items-center gap-2 lg:gap-3">
            {/* Desktop Auth Buttons - Compact */}
            <div className="hidden lg:flex items-center gap-2">
              {user ? (
                <Button
                  variant="ghost"
                  asChild
                  className="h-9 rounded-lg px-4 font-medium text-sm bg-gradient-to-r from-blue-600 to-blue-500 text-white hover:from-blue-700 hover:to-blue-600 shadow-sm hover:shadow-md hover:shadow-blue-500/20 transition-all duration-200"
                >
                  <Link href="/dashboard" className="flex items-center gap-1.5">
                    <User className="h-4 w-4" />
                    <span className="hidden xl:inline">Dashboard</span>
                  </Link>
                </Button>
              ) : (
                <>
                  <Link
                    href="/login"
                    className="hidden md:flex text-sm font-medium text-slate-600 hover:text-blue-600 transition-all duration-200 px-3 py-2 rounded-lg hover:bg-blue-50/50"
                  >
                    Sign in
                  </Link>
                  <Button
                    asChild
                    className="h-9 px-4 rounded-lg bg-gradient-to-r from-blue-600 to-blue-500 text-white hover:from-blue-700 hover:to-blue-600 font-medium text-sm transition-all duration-200 shadow-sm hover:shadow-md hover:shadow-blue-500/20"
                  >
                    <Link href="/register" className="flex items-center gap-1.5">
                      <Zap className="h-4 w-4 hidden sm:block" />
                      <span className="hidden sm:inline">Get started</span>
                      <span className="sm:hidden">Start</span>
                    </Link>
                  </Button>
                </>
              )}
            </div>

            {/* Mobile Menu Trigger */}
            <Sheet open={isOpen} onOpenChange={setIsOpen}>
              <SheetTrigger asChild>
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-10 w-10 rounded-xl hover:bg-blue-50 hover:text-blue-600 lg:hidden"
                >
                  <Menu className="h-5 w-5" />
                  <span className="sr-only">Toggle menu</span>
                </Button>
              </SheetTrigger>
              <SheetContent side="right" className="w-full sm:w-[400px] p-0 flex flex-col bg-white data-[state=open]:animate-in data-[state=open]:slide-in-from-right-full data-[state=closed]:animate-out data-[state=closed]:slide-out-to-right-full duration-300">
                <SheetTitle className="sr-only">Menu</SheetTitle>
                <div className="p-6 flex items-center gap-3 border-b border-slate-100 bg-gradient-to-r from-blue-50 to-white animate-in slide-in-from-top-2 duration-500">
                  <div className="flex items-center">
                    <span className="font-heading text-xl font-bold tracking-tight bg-gradient-to-r from-blue-600 to-blue-500 bg-clip-text text-transparent">
                      Topchart
                    </span>
                    <span className="ml-2 text-[9px] font-bold uppercase tracking-widest text-white bg-gradient-to-r from-blue-600 to-blue-500 px-2 py-0.5 rounded-full">
                      GH
                    </span>
                  </div>
                </div>

                <div className="flex-1 py-6 overflow-y-auto">
                  {/* Main Navigation */}
                  <nav className="grid gap-1 px-4 mb-6">
                    {mainNavLinks.map((link, index) => (
                      <Link
                        key={link.label}
                        href={link.href}
                        onClick={() => setIsOpen(false)}
                        className="flex items-center gap-3 px-4 py-3.5 rounded-xl hover:bg-blue-50 transition-all duration-300 text-base font-semibold text-slate-700 hover:text-blue-600 animate-in slide-in-from-right-4 fill-mode-backwards"
                        style={{ animationDelay: `${index * 75}ms`, animationDuration: '400ms' }}
                      >
                        <div className={cn("p-2 rounded-lg transition-transform duration-200", link.color)}>
                          <link.icon className="h-5 w-5" />
                        </div>
                        {link.label}
                      </Link>
                    ))}
                  </nav>

                  {/* Services Section */}
                  <div className="px-4 mb-6 animate-in fade-in slide-in-from-bottom-4 duration-700 fill-mode-backwards" style={{ animationDelay: '300ms' }}>
                    <p className="text-[11px] font-bold uppercase tracking-widest text-slate-400 mb-3 px-4">
                      Services
                    </p>
                    <nav className="grid gap-1">
                      {servicesItems.map((service, index) => {
                        const Icon = service.icon
                        return (
                          <Link
                            key={service.href}
                            href={service.href}
                            onClick={() => setIsOpen(false)}
                            className="flex items-center gap-3 px-4 py-3 rounded-xl hover:bg-blue-50/70 transition-all duration-300 text-sm font-medium text-slate-600 hover:text-blue-600 animate-in slide-in-from-right-4 fill-mode-backwards"
                            style={{ animationDelay: `${400 + index * 50}ms`, animationDuration: '300ms' }}
                          >
                            <div className={cn("p-2 rounded-lg", service.color)}>
                              <Icon className="h-4 w-4" />
                            </div>
                            <div>
                              <p className="font-medium">{service.label}</p>
                              <p className="text-xs text-slate-400">{service.description}</p>
                            </div>
                          </Link>
                        )
                      })}
                    </nav>
                  </div>

                  {/* Dashboard Section */}
                  <div className="px-4 animate-in fade-in slide-in-from-bottom-4 duration-700 fill-mode-backwards" style={{ animationDelay: '600ms' }}>
                    <p className="text-[11px] font-bold uppercase tracking-widest text-slate-400 mb-3 px-4">
                      Dashboard Links
                    </p>
                    <nav className="grid grid-cols-2 gap-2">
                      {moreItems.map((item, index) => {
                        const Icon = item.icon
                        return (
                          <Link
                            key={item.href}
                            href={item.href}
                            onClick={() => setIsOpen(false)}
                            className="flex items-center gap-2 px-3 py-2.5 rounded-xl hover:bg-blue-50/70 transition-all duration-200 text-sm font-medium text-slate-600 hover:text-blue-600 animate-in zoom-in-95 fill-mode-backwards"
                            style={{ animationDelay: `${700 + index * 40}ms`, animationDuration: '250ms' }}
                          >
                            <Icon className="h-4 w-4 text-slate-400" />
                            {item.label}
                          </Link>
                        )
                      })}
                    </nav>
                  </div>
                </div>

                <div className="p-6 border-t border-slate-100 bg-slate-50/50 animate-in slide-in-from-bottom-4 duration-500 fill-mode-backwards" style={{ animationDelay: '800ms' }}>
                  {user ? (
                    <Button
                      asChild
                      onClick={() => setIsOpen(false)}
                      className="w-full h-12 rounded-xl bg-gradient-to-r from-blue-600 to-blue-500 text-white font-semibold hover:from-blue-700 hover:to-blue-600 shadow-md hover:shadow-lg hover:shadow-blue-500/25 transition-all duration-300"
                    >
                      <Link href="/dashboard" className="flex items-center justify-center gap-2">
                        <User className="h-5 w-5" />
                        Go to Dashboard
                      </Link>
                    </Button>
                  ) : (
                    <div className="grid gap-3">
                      <Button
                        asChild
                        onClick={() => setIsOpen(false)}
                        variant="outline"
                        className="w-full h-12 rounded-xl border-slate-200 font-semibold hover:bg-slate-100 hover:border-slate-300 transition-all duration-300"
                      >
                        <Link href="/login">Sign in</Link>
                      </Button>
                      <Button
                        asChild
                        onClick={() => setIsOpen(false)}
                        className="w-full h-12 rounded-xl bg-gradient-to-r from-blue-600 to-blue-500 text-white font-semibold hover:from-blue-700 hover:to-blue-600 shadow-md hover:shadow-lg hover:shadow-blue-500/25 transition-all duration-300"
                      >
                        <Link href="/register">Create account</Link>
                      </Button>
                    </div>
                  )}
                </div>
              </SheetContent>
            </Sheet>
          </div>
        </div>
      </div>
    </header>
  )
}

